 1→import { CURRENT_PROJECT_FILE_VERSION } from '@/domain/projectVersion';
 2→
 3→export function serializeProject(project) {
 4→  return {
 5→    version: CURRENT_PROJECT_FILE_VERSION,
 6→    data: project,
 7→    savedAt: new Date().toISOString(),
 8→  };
 9→}
