  1→import { DOOR_HEIGHT, DOOR_SILL_HEIGHT, SLAB_ELEVATION, SLAB_THICKNESS, STAIR_RISERS, STAIR_RISER_HEIGHT, STAIR_TREAD_DEPTH, STAIR_WIDTH, WALL_HEIGHT, WINDOW_HEIGHT, WINDOW_SILL_HEIGHT } from '@/domain/defaults';
  2→import { sanitizeProjectPhaseReferences } from '@/domain/phaseAssignments';
  3→import { createFloor } from '@/domain/models';
  4→import { createAnnotationSettings } from '@/domain/models';
  5→import { CURRENT_PROJECT_VERSION, isSupportedProjectFileVersion } from '@/domain/projectVersion';
  6→import { normalizePhases } from '@/domain/phaseModels';
  7→import { createRoofSystem, syncRoofSystemAttachment } from '@/domain/roofModels';
  8→import {
  9→  createTrussInstance,
 10→  createPurlinSystem,
 11→  createTrussSystem,
 12→  normalizeTrussMaterial,
 13→  syncProjectTrussSystems,
 14→  TRUSS_SUPPORT_MODES,
 15→} from '@/domain/trussModels';
 16→import { getDefaultActiveFloorId, getFloorElevation, getFloorLevelIndex, getFloorToFloorHeight, getFloorTopElevation, sortFloors } from '@/domain/floorModels';
 17→import { createSheetRevision } from '@/domain/sheetModels';
 18→import {
 19→  normalizePlanLengthScale,
 20→  normalizePlanOffset,
 21→  normalizeRotationDegrees,
 22→} from '@/truss/systemTransform';
 23→
 24→export function deserializeProject(json) {
 25→  if (!json || !json.version || !json.data) {
 26→    throw new Error('Invalid project data');
 27→  }
 28→  if (!isSupportedProjectFileVersion(json.version)) {
 29→    throw new Error(`Unsupported project version: ${json.version}`);
 30→  }
 31→
 32→  let project = json.data;
 33→
 34→  // Basic validation
 35→  if (!project.id || !project.name || !Array.isArray(project.floors)) {
 36→    throw new Error('Invalid project structure');
 37→  }
 38→
 39→  if (!Array.isArray(project.sheets)) {
 40→    project.sheets = [];
 41→  }
 42→  if (project.roofSystem === undefined) {
 43→    project.roofSystem = null;
 44→  }
 45→  if (!Array.isArray(project.trussSystems)) {
 46→    project.trussSystems = [];
 47→  }
 48→  if (project.address === undefined) project.address = '';
 49→  project.documentDefaults = {
 50→    drawnBy: project.documentDefaults?.drawnBy ?? '',
 51→    checkedBy: project.documentDefaults?.checkedBy ?? '',
 52→  };
 53→  project.version = Math.max(CURRENT_PROJECT_VERSION, Number(project.version || 0));
 54→
 55→  if (project.floors.length === 0) {
 56→    project.floors = [createFloor('Ground Floor', 0)];
 57→  }
 58→
 59→  for (const floor of project.floors) {
 60→    if (!floor.id || !Array.isArray(floor.walls)) {
 61→      throw new Error('Invalid floor structure');
 62→    }
 63→  }
 64→
 65→  // Backfill missing room fields for old saves
 66→  project.floors.forEach((floor, index) => {
 67→    if (!floor.name) floor.name = index === 0 ? 'Ground Floor' : `Floor ${index}`;
 68→    if (floor.levelIndex === undefined) {
 69→      floor.levelIndex = floor.level ?? index;
 70→    }
 71→    if (floor.floorToFloorHeight === undefined) {
 72→      floor.floorToFloorHeight = WALL_HEIGHT;
 73→    }
 74→    if (floor.elevation === undefined) {
 75→      floor.elevation = floor.level ?? (floor.levelIndex * floor.floorToFloorHeight);
 76→    }
 77→    delete floor.level;
 78→
 79→    if (!floor.rooms) floor.rooms = [];
 80→    for (const room of floor.rooms) {
 81→      if (!room.points) room.points = [];
 82→      if (room.area === undefined) room.area = 0;
 83→    }
 84→  });
 85→
 86→  // Backfill door/window type fields for old saves
 87→  for (const floor of project.floors) {
 88→    if (!floor.doors) floor.doors = [];
 89→    for (const door of floor.doors) {
 90→      if (!door.type) door.type = 'swing';
 91→      if (door.height === undefined) door.height = DOOR_HEIGHT;
 92→      if (door.sillHeight === undefined) door.sillHeight = DOOR_SILL_HEIGHT;
 93→    }
 94→    if (!floor.windows) floor.windows = [];
 95→    for (const win of floor.windows) {
 96→      if (!win.type) win.type = 'standard';
 97→      if (!win.openDirection) win.openDirection = 'left';
 98→      if (win.height === undefined) win.height = WINDOW_HEIGHT;
 99→      if (win.sillHeight === undefined) win.sillHeight = WINDOW_SILL_HEIGHT;
100→    }
101→    if (!floor.columns) floor.columns = [];
102→    if (!floor.fixtures) floor.fixtures = [];
103→    if (!floor.beams) floor.beams = [];
104→    if (!floor.stairs) floor.stairs = [];
105→    if (!floor.landings) floor.landings = [];
106→    if (!floor.annotations) floor.annotations = [];
107→    floor.annotationSettings = createAnnotationSettings(floor.annotationSettings || {});
108→    // Migrate single slab → slabs array
109→    if (floor.slab !== undefined) {
110→      floor.slabs = floor.slab ? [floor.slab] : [];
111→      delete floor.slab;
112→    }
113→    if (!Array.isArray(floor.slabs)) floor.slabs = [];
114→    // Migrate single sectionCut → sectionCuts array
115→    if (floor.sectionCut !== undefined) {
116→      floor.sectionCuts = floor.sectionCut ? [floor.sectionCut] : [];
117→      delete floor.sectionCut;
118→    }
119→    if (!Array.isArray(floor.sectionCuts)) floor.sectionCuts = [];
120→    for (const wall of floor.walls) {
121→      if (wall.height === undefined) wall.height = WALL_HEIGHT;
122→      if (wall.startAttachment === undefined) wall.startAttachment = null;
123→      if (wall.endAttachment === undefined) wall.endAttachment = null;
124→    }
125→    for (const column of floor.columns) {
126→      if (column.showLabel === undefined) {
127→        column.showLabel = Boolean(column.name);
128→      }
129→    }
130→    for (const fixture of floor.fixtures) {
131→      if (!fixture.fixtureType) fixture.fixtureType = 'kitchenTop';
132→      if (fixture.x === undefined) fixture.x = 0;
133→      if (fixture.y === undefined) fixture.y = 0;
134→      if (fixture.width === undefined) fixture.width = 600;
135→      if (fixture.depth === undefined) fixture.depth = 400;
136→      if (fixture.rotation === undefined) fixture.rotation = 0;
137→      if (fixture.name === undefined) fixture.name = '';
138→    }
139→    for (const beam of floor.beams) {
140→      if (beam.floorLevel === undefined) beam.floorLevel = getFloorElevation(floor, index);
141→    }
142→    for (const stair of floor.stairs) {
143→      if (!stair.startPoint) stair.startPoint = { x: 0, y: 0 };
144→      if (stair.width === undefined) stair.width = STAIR_WIDTH;
145→      if (stair.numberOfRisers === undefined) stair.numberOfRisers = STAIR_RISERS;
146→      if (stair.riserHeight === undefined) stair.riserHeight = STAIR_RISER_HEIGHT;
147→      if (stair.treadDepth === undefined) stair.treadDepth = STAIR_TREAD_DEPTH;
148→      if (stair.direction === undefined) {
149→        stair.direction = { angle: 0 };
150→      } else if (typeof stair.direction === 'number') {
151→        stair.direction = { angle: stair.direction };
152→      } else if (stair.direction.angle === undefined) {
153→        stair.direction.angle = 0;
154→      }
155→      if (stair.floorRelation === undefined) {
156→        stair.floorRelation = { fromFloorId: floor.id, toFloorId: floor.id };
157→      } else {
158→        if (stair.floorRelation.fromFloorId === undefined) stair.floorRelation.fromFloorId = floor.id;
159→        if (stair.floorRelation.toFloorId === undefined) stair.floorRelation.toFloorId = floor.id;
160→      }
161→      if (stair.startLandingAttachment === undefined) stair.startLandingAttachment = null;
162→      if (stair.endLandingAttachment === undefined) stair.endLandingAttachment = null;
163→      if (stair.roofAccess === undefined) stair.roofAccess = null;
164→    }
165→    for (const landing of floor.landings) {
166→      if (!landing.position) landing.position = { x: 0, y: 0 };
167→      if (landing.width === undefined) landing.width = 1000;
168→      if (landing.depth === undefined) landing.depth = 1000;
169→      if (landing.thickness === undefined) landing.thickness = 200;
170→      if (landing.elevation === undefined) landing.elevation = 0;
171→      if (landing.rotation === undefined) landing.rotation = 0;
172→    }
173→    for (const annotation of floor.annotations) {
174→      if (!annotation.id) {
175→        annotation.id = `anno_${floor.id}_${Math.random().toString(36).slice(2, 8)}`;
176→      }
177→      if (!annotation.type) annotation.type = 'dimension';
178→      if (!annotation.mode) annotation.mode = 'aligned';
179→      if (!annotation.startPoint) annotation.startPoint = { x: 0, y: 0 };
180→      if (!annotation.endPoint) annotation.endPoint = { x: 0, y: 0 };
181→      if (annotation.offset === undefined) annotation.offset = 300;
182→      if (annotation.textOverride === undefined) annotation.textOverride = '';
183→    }
184→    for (const slab of floor.slabs) {
185→      if (!slab.floorId) slab.floorId = floor.id;
186→      if (!slab.boundaryPoints) slab.boundaryPoints = [];
187→      if (slab.thickness === undefined) slab.thickness = SLAB_THICKNESS;
188→      if (slab.elevation === undefined) slab.elevation = SLAB_ELEVATION;
189→      if (slab.name === undefined) slab.name = '';
190→      if (slab.type === undefined) slab.type = '';
191→    }
192→    for (const sc of floor.sectionCuts) {
193→      if (!sc.id) {
194→        sc.id = `section_${floor.id}_${Math.random().toString(36).slice(2, 8)}`;
195→      }
196→      if (!sc.startPoint) sc.startPoint = { x: 0, y: 0 };
197→      if (!sc.endPoint) sc.endPoint = { x: 1000, y: 0 };
198→      if (sc.depth === undefined) sc.depth = 2000;
199→      if (sc.label === undefined) sc.label = 'Section A-A';
200→      if (sc.direction === undefined) sc.direction = 1;
201→    }
202→  }
203→
204→  project.floors = sortFloors(project.floors).map((floor, index) => ({
205→    ...floor,
206→    levelIndex: getFloorLevelIndex(floor, index),
207→    elevation: getFloorElevation(floor, index),
208→    floorToFloorHeight: getFloorToFloorHeight(floor),
209→  }));
210→
211→  project.trussSystems = (project.trussSystems || []).map((trussSystem) => {
212→    const floor = project.floors.find((entry) => entry.id === trussSystem.floorId)
213→      || project.floors.find((entry) => entry.id === getDefaultActiveFloorId(project))
214→      || project.floors[0]
215→      || null;
216→    const floorId = floor?.id || null;
217→
218→    return {
219→      ...createTrussSystem(trussSystem.name || 'Truss System'),
220→      ...trussSystem,
221→      id: trussSystem?.id || `truss_system_${Math.random().toString(36).slice(2, 8)}`,
222→      floorId,
223→      phaseId: typeof trussSystem?.phaseId === 'string' && trussSystem.phaseId ? trussSystem.phaseId : null,
224→      baseElevation: trussSystem?.baseElevation ?? (floor ? getFloorTopElevation(floor) : 0),
225→      planRotationOffsetDegrees: normalizeRotationDegrees(trussSystem?.planRotationOffsetDegrees),
226→      planOffset: normalizePlanOffset(trussSystem?.planOffset),
227→      planLengthScale: normalizePlanLengthScale(trussSystem?.planLengthScale),
228→      purlinSystem: createPurlinSystem(trussSystem?.purlinSystem),
229→      trussInstances: (trussSystem.trussInstances || []).map((trussInstance) => ({
230→        ...createTrussInstance({ floorId }),
231→        ...trussInstance,
232→        id: trussInstance?.id || `truss_instance_${Math.random().toString(36).slice(2, 8)}`,
233→        floorId: trussInstance?.floorId || floorId,
234→        material: normalizeTrussMaterial(trussInstance?.material),
235→        startPoint: trussInstance?.startPoint ? { x: trussInstance.startPoint.x, y: trussInstance.startPoint.y } : { x: -6000, y: 0 },
236→        endPoint: trussInstance?.endPoint ? { x: trussInstance.endPoint.x, y: trussInstance.endPoint.y } : { x: 6000, y: 0 },
237→        bearingOffsets: {
238→          start: Number.isFinite(trussInstance?.bearingOffsets?.start) ? trussInstance.bearingOffsets.start : 0,
239→          end: Number.isFinite(trussInstance?.bearingOffsets?.end) ? trussInstance.bearingOffsets.end : 0,
240→        },
241→        overhangs: {
242→          start: Number.isFinite(trussInstance?.overhangs?.start) ? trussInstance.overhangs.start : 300,
243→          end: Number.isFinite(trussInstance?.overhangs?.end) ? trussInstance.overhangs.end : 300,
244→        },
245→        supportMode: trussInstance?.supportMode === TRUSS_SUPPORT_MODES.BEAM_PAIR
246→          ? TRUSS_SUPPORT_MODES.BEAM_PAIR
247→          : null,
248→        supportBeamIds: {
249→          start: typeof trussInstance?.supportBeamIds?.start === 'string' ? trussInstance.supportBeamIds.start : null,
250→          end: typeof trussInstance?.supportBeamIds?.end === 'string' ? trussInstance.supportBeamIds.end : null,
251→        },
252→        supportOffsetAlongAxis: Number.isFinite(trussInstance?.supportOffsetAlongAxis)
253→          ? Math.max(0, trussInstance.supportOffsetAlongAxis)
254→          : 0,
255→        roofAttachmentId: trussInstance?.roofAttachmentId || null,
256→      })),
257→    };
258→  });
259→  project = syncProjectTrussSystems(project);
260→
261→  if (project.roofSystem) {
262→    const roofSystem = {
263→      ...createRoofSystem(project.roofSystem.name || 'Roof'),
264→      ...project.roofSystem,
265→      trussAttachmentId: project.roofSystem.trussAttachmentId || null,
266→      pitchSource: project.roofSystem.pitchSource || (project.roofSystem.trussAttachmentId ? 'truss' : 'manual'),
267→      boundaryPolygon: (project.roofSystem.boundaryPolygon || []).map((point) => ({
268→        x: point.x,
269→        y: point.y,
270→      })),
271→      parapets: (project.roofSystem.parapets || []).map((parapet) => ({
272→        ...parapet,
273→        startPoint: parapet.startPoint ? { x: parapet.startPoint.x, y: parapet.startPoint.y } : { x: 0, y: 0 },
274→        endPoint: parapet.endPoint ? { x: parapet.endPoint.x, y: parapet.endPoint.y } : { x: 1000, y: 0 },
275→        attachment: parapet.attachment
276→          ? {
277→              type: parapet.attachment.type ?? 'roof_edge',
278→              edgeIndex: Number.isFinite(parapet.attachment.edgeIndex) ? parapet.attachment.edgeIndex : 0,
279→              startOffset: Number.isFinite(parapet.attachment.startOffset) ? parapet.attachment.startOffset : 0,
280→              endOffset: Number.isFinite(parapet.attachment.endOffset) ? parapet.attachment.endOffset : 0,
281→            }
282→          : null,
283→      })),
284→      drains: (project.roofSystem.drains || []).map((drain) => ({
285→        ...drain,
286→        position: drain.position ? { x: drain.position.x, y: drain.position.y } : { x: 0, y: 0 },
287→      })),
288→      roofOpenings: (project.roofSystem.roofOpenings || []).map((opening) => ({
289→        ...opening,
290→        boundaryPoints: (opening.boundaryPoints || []).map((point) => ({
291→          x: point.x,
292→          y: point.y,
293→        })),
294→      })),
295→      roofPlanes: (project.roofSystem.roofPlanes || []).map((plane) => ({
296→        ...plane,
297→        boundaryPoints: (plane.boundaryPoints || []).map((point) => ({
298→          x: point.x,
299→          y: point.y,
300→        })),
301→      })),
302→      roofEdges: (project.roofSystem.roofEdges || []).map((edge) => ({
303→        ...edge,
304→        startPoint: edge.startPoint ? { x: edge.startPoint.x, y: edge.startPoint.y } : { x: 0, y: 0 },
305→        endPoint: edge.endPoint ? { x: edge.endPoint.x, y: edge.endPoint.y } : { x: 1000, y: 0 },
306→        planeIds: [...new Set(edge.planeIds || [])],
307→      })),
308→      ridges: (project.roofSystem.ridges || []).map((ridge) => ({
309→        ...ridge,
310→        startPoint: ridge.startPoint ? { x: ridge.startPoint.x, y: ridge.startPoint.y } : { x: 0, y: 0 },
311→        endPoint: ridge.endPoint ? { x: ridge.endPoint.x, y: ridge.endPoint.y } : { x: 1000, y: 0 },
312→        planeIds: [...new Set(ridge.planeIds || [])],
313→      })),
314→      valleys: (project.roofSystem.valleys || []).map((valley) => ({
315→        ...valley,
316→        startPoint: valley.startPoint ? { x: valley.startPoint.x, y: valley.startPoint.y } : { x: 0, y: 0 },
317→        endPoint: valley.endPoint ? { x: valley.endPoint.x, y: valley.endPoint.y } : { x: 1000, y: 0 },
318→        planeIds: [...new Set(valley.planeIds || [])],
319→      })),
320→      hips: (project.roofSystem.hips || []).map((hip) => ({
321→        ...hip,
322→        startPoint: hip.startPoint ? { x: hip.startPoint.x, y: hip.startPoint.y } : { x: 0, y: 0 },
323→        endPoint: hip.endPoint ? { x: hip.endPoint.x, y: hip.endPoint.y } : { x: 1000, y: 0 },
324→        planeIds: [...new Set(hip.planeIds || [])],
325→      })),
326→    };
327→
328→    project.roofSystem = syncRoofSystemAttachment(project, roofSystem);
329→  }
330→
331→  for (const sheet of project.sheets) {
332→    if (!sheet.id) {
333→      sheet.id = `sheet_${Math.random().toString(36).slice(2, 8)}`;
334→    }
335→    if (sheet.title === undefined) sheet.title = '';
336→    if (sheet.paperSize === undefined) sheet.paperSize = 'A3_LANDSCAPE';
337→    if (sheet.number === undefined) sheet.number = '';
338→    if (sheet.issueDate === undefined) sheet.issueDate = '';
339→    if (sheet.scaleLabel === undefined) sheet.scaleLabel = '1:100';
340→    if (sheet.scaleMode === undefined) sheet.scaleMode = 'custom';
341→    if (sheet.layoutTemplate === undefined) sheet.layoutTemplate = 'auto';
342→    if (sheet.drawingName === undefined) sheet.drawingName = sheet.title || 'Drawing';
343→    if (sheet.projectNameOverride === undefined) sheet.projectNameOverride = '';
344→    sheet.titleBlock = {
345→      projectTitleOverride: sheet.titleBlock?.projectTitleOverride ?? '',
346→      projectAddressOverride: sheet.titleBlock?.projectAddressOverride ?? '',
347→      drawnBy: sheet.titleBlock?.drawnBy ?? '',
348→      checkedBy: sheet.titleBlock?.checkedBy ?? '',
349→    };
350→    if (!Array.isArray(sheet.revisions)) sheet.revisions = [];
351→    sheet.revisions = sheet.revisions.map((revision) => ({
352→      ...createSheetRevision(),
353→      ...revision,
354→      id: revision?.id || `revision_${sheet.id}_${Math.random().toString(36).slice(2, 8)}`,
355→    }));
356→    if (!Array.isArray(sheet.viewports)) sheet.viewports = [];
357→
358→    for (const viewport of sheet.viewports) {
359→      if (!viewport.id) {
360→        viewport.id = `viewport_${sheet.id}_${Math.random().toString(36).slice(2, 8)}`;
361→      }
362→      if (viewport.sourceView === undefined) viewport.sourceView = 'plan';
363→      if (viewport.sourceFloorId === undefined) viewport.sourceFloorId = getDefaultActiveFloorId(project);
364→      if (viewport.sourceRefId === undefined) viewport.sourceRefId = null;
365→      if (viewport.x === undefined) viewport.x = 20;
366→      if (viewport.y === undefined) viewport.y = 20;
367→      if (viewport.width === undefined) viewport.width = 160;
368→      if (viewport.height === undefined) viewport.height = 100;
369→      if (viewport.scale === undefined) viewport.scale = 100;
370→      if (viewport.title === undefined) viewport.title = '';
371→      if (viewport.rotation === undefined) viewport.rotation = 0;
372→      if (viewport.role === undefined) viewport.role = viewport.sourceView === '3d_preview'
373→        ? 'supplemental'
374→        : ((viewport.sourceView === 'plan' || viewport.sourceView === 'roof_plan' || viewport.sourceView === 'roof_drainage' || viewport.sourceView === 'truss_plan')
375→          ? 'primary'
376→          : (viewport.sourceView === 'truss_detail' ? 'detail' : 'secondary'));
377→      if (viewport.captionPosition === undefined) viewport.captionPosition = 'below';
378→      if (viewport.referenceNote === undefined) viewport.referenceNote = '';
379→      if (viewport.lockAutoLayout === undefined) viewport.lockAutoLayout = false;
380→      if (viewport.phaseId === undefined) viewport.phaseId = null;
381→      if (viewport.phaseViewMode === undefined) viewport.phaseViewMode = 'all';
382→    }
383→  }
384→
385→  project.phases = normalizePhases(project.phases || []);
386→  const validPhaseIds = new Set(project.phases.map((phase) => phase.id));
387→
388→  return {
389→    project: sanitizeProjectPhaseReferences(project, validPhaseIds),
390→    savedAt: json.savedAt,
391→  };
392→}
