 1→import { serializeProject } from './serialize';
 2→import { deserializeProject } from './deserialize';
 3→import { localStorageBackend } from './localStorageBackend';
 4→
 5→let backend = localStorageBackend;
 6→
 7→export function setBackend(b) {
 8→  backend = b;
 9→}
10→
11→export async function saveProject(project) {
12→  const serialized = serializeProject(project);
13→  await backend.save(project.id, project.name, serialized);
14→  return serialized.savedAt;
15→}
16→
17→export async function loadProject(projectId) {
18→  const json = await backend.load(projectId);
19→  if (!json) throw new Error('Project not found');
20→  return deserializeProject(json);
21→}
22→
23→export async function listProjects() {
24→  return backend.list();
25→}
26→
27→export async function deleteProject(projectId) {
28→  await backend.delete(projectId);
29→}
