143→export function getDefaultFloorName(levelIndex = 0) {
144→  if (levelIndex === 0) return 'Ground Floor';
145→  if (levelIndex < 0) return `Basement ${Math.abs(levelIndex)}`;
146→  return `Floor ${levelIndex}`;
147→}
