149→export function getFloorLevelIndex(floor, fallbackIndex = 0) {
150→  if (!floor) return fallbackIndex;
151→  if (Number.isFinite(floor.levelIndex)) return floor.levelIndex;
152→  if (Number.isFinite(floor.level)) return floor.level;
153→  return fallbackIndex;
154→}
155→
156→export function getFloorToFloorHeight(floor) {
157→  return floor?.floorToFloorHeight ?? DEFAULT_FLOOR_TO_FLOOR_HEIGHT;
158→}
159→
160→export function getFloorElevation(floor, fallbackIndex = 0) {
161→  if (!floor) return 0;
162→  if (Number.isFinite(floor.elevation)) return floor.elevation;
163→  if (Number.isFinite(floor.level)) return floor.level;
164→  return getFloorLevelIndex(floor, fallbackIndex) * getFloorToFloorHeight(floor);
165→}
166→
167→export function getFloorTopElevation(floor, fallbackIndex = 0) {
168→  return getFloorElevation(floor, fallbackIndex) + getFloorToFloorHeight(floor);
169→}
