215→export function shiftFloorElevationData(floor, deltaElevation = 0) {
216→  if (!deltaElevation) return { ...floor };
217→
218→  return {
219→    ...shiftFloorAbsoluteElements(floor, deltaElevation),
220→    elevation: getFloorElevation(floor) + deltaElevation,
221→  };
222→}
223→
224→export function shiftFloorAbsoluteElements(floor, deltaElevation = 0) {
225→  if (!deltaElevation) return { ...floor };
226→
227→  return {
228→    ...floor,
229→    beams: (floor.beams || []).map((beam) => ({
230→      ...beam,
231→      floorLevel: (beam.floorLevel ?? getFloorElevation(floor)) + deltaElevation,
232→    })),
233→    slabs: (floor.slabs || []).map((slab) => ({
234→      ...slab,
235→      elevation: (slab.elevation ?? getFloorElevation(floor)) + deltaElevation,
236→    })),
237→  };
238→}
239→
240→export function createFloorAboveHighest(existingFloors = []) {
241→  const orderedFloors = sortFloors(existingFloors);
242→  const topFloor = orderedFloors[orderedFloors.length - 1] || null;
243→  const levelIndex = topFloor ? getFloorLevelIndex(topFloor) + 1 : 0;
244→  const floorToFloorHeight = topFloor ? getFloorToFloorHeight(topFloor) : DEFAULT_FLOOR_TO_FLOOR_HEIGHT;
245→  const elevation = topFloor
246→    ? getFloorElevation(topFloor) + getFloorToFloorHeight(topFloor)
247→    : 0;
248→
249→  return createFloor(getDefaultFloorName(levelIndex), levelIndex, {
250→    elevation,
251→    floorToFloorHeight,
252→  });
253→}
254→
255→export function createDuplicatedFloor(sourceFloor) {
256→  if (!sourceFloor) return null;
257→
258→  const sourceFloorId = sourceFloor.id;
259→  const duplicatedFloorId = generateId('floor');
260→  const sourceLevelIndex = getFloorLevelIndex(sourceFloor);
261→  const sourceElevation = getFloorElevation(sourceFloor);
262→  const floorToFloorHeight = getFloorToFloorHeight(sourceFloor);
263→  const duplicatedElevation = sourceElevation + floorToFloorHeight;
264→  const elevationDelta = duplicatedElevation - sourceElevation;
265→
266→  const columns = (sourceFloor.columns || []).map(cloneColumn);
267→  const columnIdMap = new Map((sourceFloor.columns || []).map((column, index) => [column.id, columns[index].id]));
268→
269→  const walls = (sourceFloor.walls || []).map((wall) => cloneWall(wall, columnIdMap));
270→  const wallIdMap = new Map((sourceFloor.walls || []).map((wall, index) => [wall.id, walls[index].id]));
271→
272→  const landings = (sourceFloor.landings || []).map(cloneLanding);
273→  const landingIdMap = new Map((sourceFloor.landings || []).map((landing, index) => [landing.id, landings[index].id]));
274→
275→  return {
276→    id: duplicatedFloorId,
277→    name: getDefaultFloorName(sourceLevelIndex + 1),
278→    levelIndex: sourceLevelIndex + 1,
279→    elevation: duplicatedElevation,
280→    floorToFloorHeight,
281→    walls,
282→    rooms: (sourceFloor.rooms || []).map(cloneRoom),
283→    doors: (sourceFloor.doors || []).map((door) => cloneDoor(door, wallIdMap)),
284→    windows: (sourceFloor.windows || []).map((windowItem) => cloneWindow(windowItem, wallIdMap)),
285→    columns,
286→    beams: (sourceFloor.beams || []).map((beam) => cloneBeam(beam, columnIdMap, elevationDelta)),
287→    stairs: (sourceFloor.stairs || []).map((stair) => cloneStair(stair, sourceFloorId, duplicatedFloorId, landingIdMap)),
288→    landings,
289→    annotations: (sourceFloor.annotations || []).map(cloneAnnotation),
290→    annotationSettings: createAnnotationSettings(sourceFloor.annotationSettings || {}),
291→    slabs: (sourceFloor.slabs || []).map((slab) => cloneSlab(slab, duplicatedFloorId, elevationDelta)),
292→    sectionCuts: (sourceFloor.sectionCuts || []).map(cloneSectionCut),
293→  };
294→}
