 63→
 64→function normalizePhaseId(phaseId = null) {
 65→  return typeof phaseId === 'string' && phaseId ? phaseId : null;
 66→}
 67→
 68→function normalizeTrussAttachmentId(trussAttachmentId = null) {
 69→  return typeof trussAttachmentId === 'string' && trussAttachmentId ? trussAttachmentId : null;
 70→}
