 82→export function getRoofTypeLabel(roofType = 'flat') {
 83→  switch (normalizeRoofType(roofType)) {
 84→    case 'shed':
 85→      return 'Shed';
 86→    case 'gable':
 87→      return 'Gable';
 88→    case 'hip':
 89→      return 'Hip';
 90→    case 'box_gable':
 91→      return 'Box Gable';
 92→    case 'pyramid_hipped':
 93→      return 'Pyramid Hipped';
 94→    case 'domed':
 95→      return 'Domed';
 96→    case 'dropped_eaves':
 97→      return 'Dropped Eaves';
 98→    case 'custom':
 99→      return 'Custom';
100→    case 'flat':
101→    default:
102→      return 'Flat';
103→  }
104→}
