129→export function normalizeRoofPitchDirection(direction = null) {
130→  const x = Number(direction?.x);
131→  const y = Number(direction?.y);
132→  const length = Math.hypot(x, y);
133→
134→  if (!length) {
135→    return { ...ROOF_PITCH_DIRECTION };
136→  }
137→
138→  return {
139→    x: x / length,
140→    y: y / length,
141→  };
142→}
