150→function resolveCreateRoofAttachmentId(project, requestedTrussAttachmentId = null, catalog) {
151→  const normalizedRequestedId = normalizeTrussAttachmentId(requestedTrussAttachmentId);
152→  const attachableTrussSystems = getAttachableRoofTrussSystems(project, catalog);
153→  if (!attachableTrussSystems.length) return null;
154→  if (normalizedRequestedId && attachableTrussSystems.some((entry) => entry.id === normalizedRequestedId)) {
155→    return normalizedRequestedId;
156→  }
157→  return attachableTrussSystems[0].id;
