269→function collectFloorFootprintPoints(floor) {
270→  const points = [];
271→
272→  for (const wall of floor?.walls || []) {
273→    points.push(...(getWallRenderData(wall, floor.columns || []).outline || []));
274→  }
275→  for (const room of floor?.rooms || []) {
276→    points.push(...(room.points || []));
277→  }
278→  for (const slab of floor?.slabs || []) {
279→    points.push(...(slab.boundaryPoints || []));
280→  }
281→  for (const column of floor?.columns || []) {
282→    points.push(...columnOutline(column));
283→  }
284→
285→  return points.filter(Boolean);
286→}
