318→export function deriveRoofBoundaryFromProject(project) {
319→  const orderedFloors = getOrderedFloors(project);
320→  const topFloor = orderedFloors[orderedFloors.length - 1] || null;
321→  if (!topFloor) return createDefaultBoundary();
322→
323→  const slabBoundary = largestFloorSlabBoundary(topFloor);
324→  if (slabBoundary?.length >= 3) return slabBoundary;
325→
326→  return boundsToPolygon(collectFloorFootprintPoints(topFloor));
327→}
