433→function normalizeParapets(parapets = []) {
434→  return parapets.map((parapet) => ({
435→    ...createParapet(),
436→    ...parapet,
437→    id: parapet?.id || generateId('parapet'),
438→    startPoint: clonePoint(parapet?.startPoint),
439→    endPoint: clonePoint(parapet?.endPoint),
440→    attachment: parapet?.attachment
441→      ? {
442→          type: parapet.attachment.type ?? 'roof_edge',
443→          edgeIndex: Number.isFinite(parapet.attachment.edgeIndex) ? parapet.attachment.edgeIndex : 0,
444→          startOffset: Number.isFinite(parapet.attachment.startOffset) ? parapet.attachment.startOffset : 0,
445→          endOffset: Number.isFinite(parapet.attachment.endOffset) ? parapet.attachment.endOffset : 0,
446→        }
447→      : null,
448→  }));
449→}
