451→function normalizeDrains(drains = []) {
452→  return drains.map((drain) => ({
453→    ...createDrain(),
454→    ...drain,
455→    id: drain?.id || generateId('drain'),
456→    position: clonePoint(drain?.position),
457→  }));
458→}
