460→function normalizeRoofOpenings(roofOpenings = []) {
461→  return roofOpenings.map((opening) => ({
462→    ...createRoofOpening(),
463→    ...opening,
464→    id: opening?.id || generateId('roof_opening'),
465→    boundaryPoints: clonePoints(opening?.boundaryPoints || []),
466→  }));
467→}
