469→function normalizeRoofPlanes(roofPlanes = [], roofType, boundaryPolygon, baseElevation) {
470→  const normalized = (roofPlanes || [])
471→    .map((plane, index) => ({
472→      ...createRoofPlane(
473→        (plane?.boundaryPoints || []).length >= 3
474→          ? plane.boundaryPoints
475→          : (index === 0 ? boundaryPolygon : []),
476→        {
477→          ...plane,
478→          id: plane?.id || generateId('roof_plane'),
479→          baseElevation: isFiniteNumber(plane?.baseElevation) ? plane.baseElevation : baseElevation,
480→        }
481→      ),
482→      boundaryPoints: clonePoints(plane?.boundaryPoints || (index === 0 ? boundaryPolygon : [])),
483→    }))
484→    .filter((plane) => isValidRoofPolygon(plane.boundaryPoints));
485→
486→  if (normalizeRoofType(roofType) === 'custom' && !normalized.length && isValidRoofPolygon(boundaryPolygon)) {
487→    return [createRoofPlane(boundaryPolygon, { name: 'Plane 1', baseElevation })];
488→  }
489→
490→  return normalized;
491→}
492→
493→function normalizeRoofEdges(roofEdges = []) {
494→  return (roofEdges || []).map((edge) => ({
495→    ...createRoofEdge(edge?.startPoint, edge?.endPoint, edge),
496→    id: edge?.id || generateId('roof_edge'),
497→    startPoint: clonePoint(edge?.startPoint),
498→    endPoint: clonePoint(edge?.endPoint),
499→    planeIds: [...new Set(edge?.planeIds || [])],
500→    edgeRole: normalizeRoofEdgeRole(edge?.edgeRole ?? edge?.role),
501→  }));
502→}
503→
504→function normalizeRelationships(collection = [], createFactory) {
505→  return (collection || []).map((entry) => {
506→    const normalized = createFactory(entry);
507→    return {
508→      ...normalized,
509→      ...entry,
510→      id: entry?.id || normalized.id,
511→      startPoint: clonePoint(entry?.startPoint),
512→      endPoint: clonePoint(entry?.endPoint),
513→      planeIds: [...new Set(entry?.planeIds || [])],
514→    };
515→  });
516→}
