587→export function createRoofSystem(name = 'Roof', options = {}) {
588→  const boundaryPolygon = clonePoints(options.boundaryPolygon || []);
589→  const trussAttachmentId = normalizeTrussAttachmentId(options.trussAttachmentId);
590→  const attachmentOffset = isFiniteNumber(options.attachmentOffset)
591→    ? options.attachmentOffset
592→    : 0;
593→  const roofSystem = {
594→    id: options.id || generateId('roof'),
595→    roofType: normalizeRoofType(options.roofType ?? 'flat'),
596→    name,
597→    phaseId: normalizePhaseId(options.phaseId),
598→    trussAttachmentId,
599→    pitchSource: normalizeRoofPitchSource(options.pitchSource, trussAttachmentId),
600→    attachedShapeProfile: normalizeAttachedShapeProfile(options.attachedShapeProfile, options.roofType),
601→    baseElevation: options.baseElevation ?? 0,
602→    attachmentOffset,
603→    boundaryPolygon: boundaryPolygon.length ? boundaryPolygon : createDefaultBoundary(),
604→    slabThickness: options.slabThickness ?? ROOF_SLAB_THICKNESS,
605→    finishSlope: options.finishSlope ?? ROOF_FINISH_SLOPE,
606→    pitch: createRoofPitch(options.pitch),
607→    parapets: normalizeParapets(options.parapets || []),
608→    drains: normalizeDrains(options.drains || []),
609→    roofOpenings: normalizeRoofOpenings(options.roofOpenings || []),
610→    roofPlanes: normalizeRoofPlanes(
611→      options.roofPlanes || [],
612→      options.roofType ?? 'flat',
613→      boundaryPolygon.length ? boundaryPolygon : createDefaultBoundary(),
614→      options.baseElevation ?? 0
615→    ),
616→    roofEdges: normalizeRoofEdges(options.roofEdges || []),
617→    ridges: normalizeRelationships(options.ridges || [], createRidge),
618→    valleys: normalizeRelationships(options.valleys || [], createValley),
619→    hips: normalizeRelationships(options.hips || [], createHip),
620→  };
621→
622→  const collections = normalizeRoofSystemCollections(roofSystem);
623→  return {
624→    ...roofSystem,
625→    ...collections,
626→  };
627→}
